class Solution {
    public int primePalindrome(int n) {
        int left = 2, right = n;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            boolean isPalindrome = true;
            for (int i = 1; i <= mid / 1000000; i++) {
                if (mid % i == 0) {
                    isPalindrome = false;
                    break;
                }
            }
            if (isPalindrome) {
                if (isPrime(mid)) {
                    return mid;
                }
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
    }

    private boolean isPrime(int num) {
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
}
